def ecdf(data):
    """Compute the empirical cumulative distribution function."""
    x = np.sort(data)
    n = len(x)
    y = np.arange(1, n + 1) / n
    return (x, y)

def longest_interval(data, threshold):
    """
    Finds the longest interval [low, high) such that ECDF(x) < threshold
    for any x in [low, high).
    """
    (x, y) = ecdf(data)
    longest_low = None
    longest_high = None
    max_len = 0
    for i in range(len(x)):
        if y[i] < threshold:
            low = x[i]
            for j in range(i + 1, len(x)):
                if y[j] >= threshold:
                    high = x[j]
                    interval_len = high - low
                    if interval_len > max_len:
                        max_len = interval_len
                        longest_low = low
                        longest_high = high
                    break
            else:
                longest_low = low
                longest_high = x[-1]
                interval_len = x[-1] - low
                if interval_len > max_len:
                    max_len = interval_len
    return (longest_low, longest_high)

